1	<!--
2	  @component Systemd Journal Log Viewer (Admin only)
3	
4	  Properties:
5	  - `isAdmin Bool!`: Is currently logged in user admin authority
6	-->
7	
8	<script>
9	  import {
10	    Card,
11	    CardHeader,
12	    CardBody,
13	    Table,
14	    Input,
15	    Button,
16	    Badge,
17	    Spinner,
18	    InputGroup,
19	    InputGroupText,
20	    Icon,
21	  } from "@sveltestrap/sveltestrap";
22	
23	  let { isAdmin } = $props();
24	
25	  const timeRanges = [
26	    { label: "Last 15 minutes", value: "15 min ago" },
27	    { label: "Last 1 hour", value: "1 hour ago" },
28	    { label: "Last 6 hours", value: "6 hours ago" },
29	    { label: "Last 24 hours", value: "24 hours ago" },
30	    { label: "Last 7 days", value: "7 days ago" },
31	  ];
32	
33	  const levels = [
34	    { label: "All levels", value: "" },
35	    { label: "Emergency (0)", value: "0" },
36	    { label: "Alert (1)", value: "1" },
37	    { label: "Critical (2)", value: "2" },
38	    { label: "Error (3)", value: "3" },
39	    { label: "Warning (4)", value: "4" },
40	    { label: "Notice (5)", value: "5" },
41	    { label: "Info (6)", value: "6" },
42	    { label: "Debug (7)", value: "7" },
43	  ];
44	
45	  const refreshIntervals = [
46	    { label: "Off", value: 0 },
47	    { label: "5s", value: 5000 },
48	    { label: "10s", value: 10000 },
49	    { label: "30s", value: 30000 },
50	  ];
51	
52	  let since = $state("1 hour ago");
53	  let level = $state("");
54	  let search = $state("");
55	  let linesParam = $state("200");
56	  let refreshInterval = $state(0);
57	  let entries = $state([]);
58	  let loading = $state(false);
59	  let error = $state(null);
60	  let timer = $state(null);
61	
62	  function levelColor(priority) {
63	    if (priority <= 2) return "danger";
64	    if (priority === 3) return "warning";
65	    if (priority === 4) return "info";
66	    if (priority <= 6) return "secondary";
67	    return "light";
68	  }
69	
70	  function levelName(priority) {
71	    const names = [
72	      "EMERG",
73	      "ALERT",
74	      "CRIT",
75	      "ERR",
76	      "WARN",
77	      "NOTICE",
78	      "INFO",
79	      "DEBUG",
80	    ];
81	    return names[priority] || "UNKNOWN";
82	  }
83	
84	  function formatTimestamp(usec) {
85	    if (!usec) return "";
86	    const ms = parseInt(usec) / 1000;
87	    const d = new Date(ms);
88	    return d.toLocaleString();
89	  }
90	
91	  async function fetchLogs() {
92	    loading = true;
93	    error = null;
94	    try {
95	      const params = new URLSearchParams();
96	      params.set("since", since);
97	      params.set("lines", linesParam);
98	      if (level) params.set("level", level);
99	      if (search.trim()) params.set("search", search.trim());
100	
101	      const resp = await fetch(`/frontend/logs/?${params.toString()}`);
102	      if (!resp.ok) {
103	        const body = await resp.json();
104	        throw new Error(body.error || `HTTP ${resp.status}`);
105	      }
106	      entries = await resp.json();
107	    } catch (e) {
108	      error = e.message;
109	      entries = [];
110	    } finally {
111	      loading = false;
112	    }
113	  }
114	
115	  function setupAutoRefresh(interval) {
116	    if (timer) {
117	      clearInterval(timer);
118	      timer = null;
119	    }
120	    if (interval > 0) {
121	      timer = setInterval(fetchLogs, interval);
122	    }
123	  }
124	
125	  $effect(() => {
126	    setupAutoRefresh(refreshInterval);
127	    return () => {
128	      if (timer) clearInterval(timer);
129	    };
130	  });
131	
132	  // Fetch on mount
133	  $effect(() => {
134	    fetchLogs();
135	  });
136	</script>
137	
138	{#if !isAdmin}
139	  <Card>
140	    <CardBody>
141	      <p>Access denied. Admin privileges required.</p>
142	    </CardBody>
143	  </Card>
144	{:else}
145	  <Card class="mb-3">
146	    <CardHeader>
147	      <div class="d-flex flex-wrap align-items-center gap-2">
148	        <InputGroup size="sm" style="max-width: 200px;">
149	          <Input type="select" bind:value={since}>
150	            {#each timeRanges as tr}
151	              <option value={tr.value}>{tr.label}</option>
152	            {/each}
153	          </Input>
154	        </InputGroup>
155	
156	        <InputGroup size="sm" style="max-width: 180px;">
157	          <Input type="select" bind:value={level}>
158	            {#each levels as lv}
159	              <option value={lv.value}>{lv.label}</option>
160	            {/each}
161	          </Input>
162	        </InputGroup>
163	
164	        <InputGroup size="sm" style="max-width: 150px;">
165	          <InputGroupText>Lines</InputGroupText>
166	          <Input type="select" bind:value={linesParam}>
167	            <option value="100">100</option>
168	            <option value="200">200</option>
169	            <option value="500">500</option>
170	            <option value="1000">1000</option>
171	          </Input>
172	        </InputGroup>
173	
174	        <InputGroup size="sm" style="max-width: 250px;">
175	          <Input
176	            type="text"
177	            placeholder="Search..."
178	            bind:value={search}
179	            onkeydown={(e) => {
180	              if (e.key === "Enter") fetchLogs();
181	            }}
182	          />
183	        </InputGroup>
184	
185	        <Button
186	          size="sm"
187	          color="primary"
188	          onclick={fetchLogs}
189	          disabled={loading}
190	        >
191	          {#if loading}
192	            <Spinner size="sm" />
193	          {:else}
194	            <Icon name="arrow-clockwise" />
195	          {/if}
196	          Refresh
197	        </Button>
198	
199	        <InputGroup size="sm" style="max-width: 140px;">
200	          <InputGroupText>Auto</InputGroupText>
201	          <Input type="select" bind:value={refreshInterval}>
202	            {#each refreshIntervals as ri}
203	              <option value={ri.value}>{ri.label}</option>
204	            {/each}
205	          </Input>
206	        </InputGroup>
207	
208	        {#if entries.length > 0}
209	          <small class="text-muted ms-auto">{entries.length} entries</small>
210	        {/if}
211	      </div>
212	    </CardHeader>
213	    <CardBody style="padding: 0;">
214	      {#if error}
215	        <div class="alert alert-danger m-3">{error}</div>
216	      {/if}
217	
218	      <div style="max-height: 75vh; overflow-y: auto;">
219	        <Table size="sm" striped hover responsive class="mb-0">
220	          <thead class="sticky-top bg-white">
221	            <tr>
222	              <th style="width: 170px;">Timestamp</th>
223	              <th style="width: 80px;">Level</th>
224	              <th>Message</th>
225	            </tr>
226	          </thead>
227	          <tbody style="font-family: monospace; font-size: 0.85rem;">
228	            {#each entries as entry}
229	              <tr>
230	                <td class="text-nowrap">{formatTimestamp(entry.timestamp)}</td>
231	                <td
232	                  ><Badge color={levelColor(entry.priority)}
233	                    >{levelName(entry.priority)}</Badge
234	                  ></td
235	                >
236	                <td style="white-space: pre-wrap; word-break: break-all;"
237	                  >{entry.message}</td
238	                >
239	              </tr>
240	            {:else}
241	              {#if !loading && !error}
242	                <tr
243	                  ><td colspan="3" class="text-center text-muted py-3"
244	                    >No log entries found</td
245	                  ></tr
246	                >
247	              {/if}
248	            {/each}
249	          </tbody>
250	        </Table>
251	      </div>
252	    </CardBody>
253	  </Card>
254	{/if}
255
